== Japanese Wikipedia content ==
{{統合文字|{{jalink|灘|Q11566792}}}}
{{Infobox ocean
| name = 玄界灘
| image = View of Katsushima Island and Oshima Island from Ferry "Oshima".JPG
| image_size = 250
| caption = 勝島と{{jalink|大島 (福岡県)|Q11434813|筑前大島}}
| coords = {{coord|34|0|N|130|0|E|region:JP_type:waterbody|display =inline,title}}
| part_of = {{jalink|日本海|Q27092}} / {{jalink|東シナ海|Q45341}}
| oceans = {{jalink|太平洋|Q98}}
| basin_countries = {{JPN}}
| cities = {{jalink|福岡市|Q26600|福岡}}、{{jalink|宗像市|Q819603|宗像}}、{{jalink|糸島市|Q1011145|糸島}}、{{jalink|古賀市|Q768356|古賀}}、{{jalink|唐津市|Q738275|唐津}}など
| pushpin_map = Japan#East China Sea#Japan Kyushu
| pushpin_map_caption = 玄界灘（およその位置）
| latd = 34 |latm = 0 |latNS = N
| longd = 130 |longm = 0 |longEW = E
